SELECT * FROM /* 从日志表 */ maintenancelog WHERE 1=1
/* 指定查询条件(对应字段必须包含相关字符串) */
AND ( id LIKE CONCAT('%', #{match}, '%') OR subject LIKE CONCAT('%', #{match}, '%') OR content LIKE CONCAT('%', #{match}, '%') OR userId LIKE CONCAT('%', #{match}, '%') )
/* 指定排序方式 */ ORDER BY
-- 假设按id降序排序，根据实际情况选择字段 `time` DESC
-- 默认升序排序 `time` ASC
/* 指定分页 */ LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM /* 从日志表 */ maintenancelog WHERE 1=1
/* 指定查询条件(对应字段必须包含相关字符串) */
AND ( id LIKE CONCAT('%', #{match}, '%') OR subject LIKE CONCAT('%', #{match}, '%') OR content LIKE CONCAT('%', #{match}, '%') OR userId LIKE CONCAT('%', #{match}, '%') )
